var e=[{id:`L2_1`,type:`dialog`,speaker:`ASCELLA_ZODIAC_NULL_NULL`,text:{KOREA:`내 몸도, 마음도… 내가 가진 거 전~부 줄 테니까, 앞으로도 날 거칠게 다뤄줘.`,JPN:`アタシの体も、心も……ぜ～んぶ君にあげる。だから、これからも乱暴に扱って。`,ENG:`My body, my heart... everything I've got, I'll give it all to you. So keep treating me rough, okay?`,TWN:`我的身體、我的心…我擁有的一切都～給你。所以，之後也要繼續粗暴地對待我喔。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ASCELLA_ZODIAC_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ASCELLA_ZODIAC_NULL_NULL`,text:{KOREA:`너를 노리는 녀석들이랑 싸우면, 엄청 기분 좋을 거야!`,JPN:`君を狙ってくるやつらと戦ったら、きっとすっごく気持ちいいと思うんだ！`,ENG:`Fighting the ones who come for you will feel amazing!`,TWN:`跟那些盯上你的人戰鬥，一定會開心到不行！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ASCELLA_ZODIAC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};